<!-- 功能说明
管理端核心订单管理页面，支持订单多条件筛选、订单状态操作（确认、发货、售后处理）、
订单详情查看、数据导出，核心对接订单管理相关接口，适配管理员 / 客服权限。 -->
<template>
  <view class="order-manage-container">
    <!-- 页面头部 -->
    <view class="page-header">
      <text class="header-title">订单管理</text>
      <button class="export-btn" @click="exportOrders" v-if="userRole === 'ADMIN'">导出订单</button>
    </view>

    <!-- 筛选区域 -->
    <view class="filter-container">
      <!-- 状态筛选 -->
      <scroll-view class="status-scroll" scroll-x>
        <view 
          class="status-item" 
          v-for="(item, index) in statusList" 
          :key="index"
          :class="{ active: currentStatus === item.value }"
          @click="switchStatus(item.value)"
        >
          <text class="status-text">{{item.label}}</text>
        </view>
      </scroll-view>

      <!-- 搜索区域 -->
      <view class="search-container">
        <image src="/static/images/icon-search.png" class="search-icon"></image>
        <input 
          class="search-input" 
          v-model="searchKey" 
          placeholder="请输入订单号/用户昵称搜索"
          @input="debounceSearch"
        ></input>
        <button class="reset-btn" @click="resetSearch" v-if="searchKey">重置</button>
      </view>

      <!-- 时间筛选 -->
      <view class="date-filter">
        <text class="filter-label">下单时间：</text>
        <view class="date-picker-group">
          <picker 
            mode="date"
            :value="startDate"
            @change="handleStartDateChange"
            class="date-picker"
          >
            <view class="picker-text">{{startDate || '开始日期'}}</view>
          </picker>
          <text class="date-separator">-</text>
          <picker 
            mode="date"
            :value="endDate"
            @change="handleEndDateChange"
            class="date-picker"
          >
            <view class="picker-text">{{endDate || '结束日期'}}</view>
          </picker>
        </view>
      </view>
    </view>

    <!-- 订单列表 -->
    <view class="order-list" v-if="orderList.length > 0">
      <view class="order-item" v-for="(order, index) in orderList" :key="index">
        <!-- 订单头部 -->
        <view class="order-header">
          <view class="order-left">
            <text class="order-no">订单号：{{order.orderNo}}</text>
            <text class="order-time">下单时间：{{formatTime(order.createTime)}}</text>
          </view>
          <text class="order-status" :class="getStatusClass(order.status)">{{getStatusLabel(order.status)}}</text>
        </view>

        <!-- 订单详情 -->
        <view class="order-detail">
          <view class="user-info">
            <image src="/static/images/icon-user.png" class="user-icon"></image>
            <text class="user-name">{{order.userNickname || '匿名用户'}}</text>
            <text class="user-phone">{{order.receiverPhone}}</text>
          </view>

          <view class="goods-list">
            <view class="goods-item" v-for="(goods, gIndex) in order.orderItems" :key="gIndex">
              <image :src="goods.productImage" mode="aspectFill" class="goods-img"></image>
              <view class="goods-info">
                <text class="goods-name">{{goods.productName}}</text>
                <text class="goods-spec">规格：{{goods.specText || '默认规格'}}</text>
                <text class="goods-count">x{{goods.quantity}}</text>
              </view>
              <text class="goods-price">¥{{(goods.price * goods.quantity).toFixed(2)}}</text>
            </view>
          </view>

          <view class="order-amount">
            <text class="amount-label">实付款：</text>
            <text class="amount-value">¥{{order.totalAmount.toFixed(2)}}</text>
          </view>
        </view>

        <!-- 操作按钮 -->
        <view class="operation-group">
          <button class="oper-btn detail-btn" @click="goToOrderDetail(order.orderNo)">查看详情</button>
          <template v-if="order.status === 'PENDING_CONFIRM'">
            <button class="oper-btn confirm-btn" @click="confirmOrder(order.orderNo, index)">确认订单</button>
            <button class="oper-btn cancel-btn" @click="cancelOrder(order.orderNo, index)">取消订单</button>
          </template>
          <template v-if="order.status === 'PENDING_SHIPMENT'">
            <button class="oper-btn ship-btn" @click="showShipModal(order.orderNo, index)">发货</button>
          </template>
          <template v-if="order.status === 'AFTER_SALE'">
            <button class="oper-btn agree-btn" @click="agreeAfterSale(order.orderNo, index)">同意售后</button>
            <button class="oper-btn refuse-btn" @click="refuseAfterSale(order.orderNo, index)">拒绝售后</button>
          </template>
        </view>
      </view>
    </view>

    <!-- 空列表状态 -->
    <view class="empty-list" v-else>
      <image src="/static/images/empty-order.png" class="empty-img"></image>
      <text class="empty-text">暂无符合条件的订单</text>
    </view>

    <!-- 加载更多 -->
    <view class="load-more" v-if="isLoadingMore">
      <text class="load-text">加载中...</text>
    </view>

    <!-- 发货弹窗 -->
    <uni-modal 
      title="发货操作" 
      :visible="shipModalVisible" 
      @confirm="confirmShip"
      @cancel="hideShipModal"
    >
      <view class="ship-form">
        <view class="form-item">
          <text class="form-label">快递公司：</text>
          <picker 
          :range="expressList"
          :value="selectedExpressIndex"
          @change="handleExpressChange"
          class="express-picker"
        >
            <view class="picker-text">{{expressList[selectedExpressIndex] || '请选择快递公司'}}</view>
          </picker>
        </view>
        <view class="form-item">
          <text class="form-label">物流单号：</text>
          <input 
            class="form-input" 
            v-model="logisticsNo" 
            placeholder="请输入物流单号"
            maxlength="50"
          ></input>
        </view>
      </view>
    </uni-modal>
  </view>
</template>

<script setup>
import { ref, computed } from 'vue';
import { onLoad, onShow } from '@dcloudio/uni-app';
import { useUserStore } from '@/store/modules/userStore';
import request from '@/utils/request';

// 状态管理
const userStore = useUserStore();

// 页面数据
const userRole = computed(() => userStore.userInfo.role || 'CUSTOMER_SERVICE'); // 管理员/客服角色
const statusList = ref([
  { label: '全部', value: '' },
  { label: '待确认', value: 'PENDING_CONFIRM' },
  { label: '待发货', value: 'PENDING_SHIPMENT' },
  { label: '待收货', value: 'PENDING_RECEIPT' },
  { label: '已完成', value: 'COMPLETED' },
  { label: '已取消', value: 'CANCELLED' },
  { label: '售后中', value: 'AFTER_SALE' }
]);
const currentStatus = ref(''); // 当前选中状态
const searchKey = ref(''); // 搜索关键词
const startDate = ref(''); // 开始日期
const endDate = ref(''); // 结束日期
const orderList = ref([]); // 订单列表
const pageNum = ref(1);
const pageSize = ref(10);
const isLoadingMore = ref(false);
const hasMore = ref(true);
let searchTimer = null; // 防抖定时器

// 发货弹窗相关
const shipModalVisible = ref(false);
const selectedOrderNo = ref('');
const selectedOrderIndex = ref(-1);
const expressList = ref(['顺丰速运', '京东物流', '中通快递', '圆通快递', '申通快递', '韵达快递', '极兔速递']);
const selectedExpressIndex = ref(0);
const logisticsNo = ref('');

// 页面加载时获取订单列表
onLoad(() => {
  if (!userStore.token || !['ADMIN', 'CUSTOMER_SERVICE'].includes(userRole.value)) {
    uni.navigateTo({ url: '/pages/admin/login' });
    return;
  }
  getOrderList();
});

onShow(() => {
  // 操作后刷新列表
  pageNum.value = 1;
  orderList.value = [];
  getOrderList();
});

// 获取订单列表
const getOrderList = async () => {
  if (!hasMore.value) return;
  isLoadingMore.value = true;

  // 构造请求参数
  const params = {
    pageNum: pageNum.value,
    pageSize: pageSize.value,
    status: currentStatus.value,
    keyword: searchKey.value.trim(),
    startDate: startDate.value,
    endDate: endDate.value
  };

  try {
    const res = await request({
      url: '/api/admin/order/list',
      method: 'GET',
      params
    });
    if (res.success) {
      const data = res.data.list || [];
      if (pageNum.value === 1) {
        orderList.value = data;
      } else {
        orderList.value = [...orderList.value, ...data];
      }
      hasMore.value = pageNum.value * pageSize.value < res.data.total;
      pageNum.value += 1;
    }
  } catch (error) {
    uni.showToast({ title: '订单列表加载失败', icon: 'none' });
  } finally {
    isLoadingMore.value = false;
  }
};

// 切换订单状态
const switchStatus = (status) => {
  currentStatus.value = status;
  pageNum.value = 1;
  orderList.value = [];
  getOrderList();
};

// 搜索防抖
const debounceSearch = () => {
  clearTimeout(searchTimer);
  searchTimer = setTimeout(() => {
    pageNum.value = 1;
    orderList.value = [];
    getOrderList();
  }, 500);
};

// 重置搜索
const resetSearch = () => {
  searchKey.value = '';
  pageNum.value = 1;
  orderList.value = [];
  getOrderList();
};

// 开始日期选择
const handleStartDateChange = (e) => {
  startDate.value = e.detail.value;
  pageNum.value = 1;
  orderList.value = [];
  getOrderList();
};

// 结束日期选择
const handleEndDateChange = (e) => {
  endDate.value = e.detail.value;
  pageNum.value = 1;
  orderList.value = [];
  getOrderList();
};

// 格式化时间
const formatTime = (time) => {
  if (!time) return '';
  const date = new Date(time);
  return `${date.getFullYear()}-${(date.getMonth() + 1).toString().padStart(2, '0')}-${date.getDate().toString().padStart(2, '0')} ${date.getHours().toString().padStart(2, '0')}:${date.getMinutes().toString().padStart(2, '0')}`;
};

// 根据状态获取标签
const getStatusLabel = (status) => {
  const statusMap = {
    'PENDING_CONFIRM': '待确认',
    'PENDING_SHIPMENT': '待发货',
    'PENDING_RECEIPT': '待收货',
    'COMPLETED': '已完成',
    'CANCELLED': '已取消',
    'AFTER_SALE': '售后中'
  };
  return statusMap[status] || '未知状态';
};

// 根据状态获取样式类
const getStatusClass = (status) => {
  const classMap = {
    'PENDING_CONFIRM': 'status-pending',
    'PENDING_SHIPMENT': 'status-ship',
    'PENDING_RECEIPT': 'status-receipt',
    'COMPLETED': 'status-complete',
    'CANCELLED': 'status-cancel',
    'AFTER_SALE': 'status-after-sale'
  };
  return classMap[status] || '';
};

// 查看订单详情
const goToOrderDetail = (orderNo) => {
  uni.navigateTo({ url: `/pages/admin/order/detail?orderNo=${orderNo}` });
};

// 确认订单
const confirmOrder = async (orderNo, index) => {
  uni.showModal({
    title: '提示',
    content: '确定要确认该订单吗？',
    success: async (res) => {
      if (res.confirm) {
        try {
          const res = await request({
            url: '/api/admin/order/confirm',
            method: 'PUT',
            data: { orderNo }
          });
          if (res.success) {
            uni.showToast({ title: '订单确认成功' });
            orderList.value[index].status = 'PENDING_SHIPMENT';
          } else {
            uni.showToast({ title: res.message || '订单确认失败', icon: 'none' });
          }
        } catch (error) {
          uni.showToast({ title: '网络异常，操作失败', icon: 'none' });
        }
      }
    }
  });
};

// 取消订单
const cancelOrder = async (orderNo, index) => {
  uni.showModal({
    title: '提示',
    content: '确定要取消该订单吗？取消后将触发退款流程',
    confirmColor: '#F53F3F',
    success: async (res) => {
      if (res.confirm) {
        try {
          const res = await request({
            url: '/api/admin/order/cancel',
            method: 'PUT',
            data: { orderNo }
          });
          if (res.success) {
            uni.showToast({ title: '订单取消成功' });
            orderList.value[index].status = 'CANCELLED';
          } else {
            uni.showToast({ title: res.message || '订单取消失败', icon: 'none' });
          }
        } catch (error) {
          uni.showToast({ title: '网络异常，操作失败', icon: 'none' });
        }
      }
    }
  });
};

// 显示发货弹窗
const showShipModal = (orderNo, index) => {
  selectedOrderNo.value = orderNo;
  selectedOrderIndex.value = index;
  selectedExpressIndex.value = 0;
  logisticsNo.value = '';
  shipModalVisible.value = true;
};

// 隐藏发货弹窗
const hideShipModal = () => {
  shipModalVisible.value = false;
};

// 快递公司选择变更
const handleExpressChange = (event) => {
  selectedExpressIndex.value = event.detail.value;
};

// 确认发货
const confirmShip = async () => {
  if (!logisticsNo.value.trim()) {
    uni.showToast({ title: '请输入物流单号', icon: 'none' });
    return;
  }

  try {
    const res = await request({
      url: '/api/admin/order/deliver',
      method: 'PUT',
      data: {
        orderNo: selectedOrderNo.value,
        expressCompany: expressList.value[selectedExpressIndex.value],
        expressNo: logisticsNo.value.trim()
      }
    });

    if (res.success) {
      uni.showToast({ title: '发货成功' });
      orderList.value[selectedOrderIndex.value].status = 'PENDING_RECEIPT';
      hideShipModal();
    } else {
      uni.showToast({ title: res.message || '发货失败', icon: 'none' });
    }
  } catch (error) {
    uni.showToast({ title: '网络异常，操作失败', icon: 'none' });
  }
};

// 同意售后
const agreeAfterSale = async (orderNo, index) => {
  uni.showModal({
    title: '提示',
    content: '确定要同意该售后申请吗？',
    success: async (res) => {
      if (res.confirm) {
        try {
          const res = await request({
            url: '/api/admin/order/afterSale/agree',
            method: 'PUT',
            data: { orderNo }
          });
          if (res.success) {
            uni.showToast({ title: '同意售后成功' });
            orderList.value[index].status = 'COMPLETED';
          } else {
            uni.showToast({ title: res.message || '操作失败', icon: 'none' });
          }
        } catch (error) {
          uni.showToast({ title: '网络异常，操作失败', icon: 'none' });
        }
      }
    }
  });
};

// 拒绝售后
const refuseAfterSale = async (orderNo, index) => {
  uni.showModal({
    title: '提示',
    content: '确定要拒绝该售后申请吗？',
    confirmColor: '#F53F3F',
    success: async (res) => {
      if (res.confirm) {
        try {
          const res = await request({
            url: '/api/admin/order/afterSale/refuse',
            method: 'PUT',
            data: { orderNo }
          });
          if (res.success) {
            uni.showToast({ title: '拒绝售后成功' });
            orderList.value[index].status = 'COMPLETED';
          } else {
            uni.showToast({ title: res.message || '操作失败', icon: 'none' });
          }
        } catch (error) {
          uni.showToast({ title: '网络异常，操作失败', icon: 'none' });
        }
      }
    }
  });
};

// 导出订单
const exportOrders = async () => {
  uni.showLoading({ title: '导出中' });
  try {
    const params = {
      status: currentStatus.value,
      keyword: searchKey.value.trim(),
      startDate: startDate.value,
      endDate: endDate.value
    };

    const res = await request({
      url: '/api/admin/order/export',
      method: 'GET',
      params,
      responseType: 'blob'
    });

    // 下载文件
    const blob = new Blob([res.data], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `订单数据_${new Date().getTime()}.xlsx`;
    a.click();
    window.URL.revokeObjectURL(url);

    uni.showToast({ title: '导出成功' });
  } catch (error) {
    uni.showToast({ title: '导出失败', icon: 'none' });
  } finally {
    uni.hideLoading();
  }
};
</script>

